import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback, useRef } from 'react';
import { Header } from './components/Header';
import { TransformVisual } from './components/TransformVisual';
import { FileUploader } from './components/FileUploader';
import { ProgressIndicator } from './components/ProgressIndicator';
import { aiEnhanceDocument } from './services/geminiService';
import { generatePDF } from './utils/pdfHelper';

export type Status = 'idle' | 'uploading' | 'processing' | 'generating' | 'completed' | 'error';

const App: React.FC = () => {
  const [status, setStatus] = useState<Status>('idle');
  const [fileName, setFileName] = useState<string | null>(null);
  const [content, setContent] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    setStatus('uploading');

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      setContent(text);
      setStatus('idle');
    };
    reader.onerror = () => {
      setError("Failed to read the file.");
      setStatus('error');
    };
    reader.readAsText(file);
  };

  const startTransformation = async () => {
    if (!content) {
      setError("Please select a document first.");
      return;
    }

    try {
      setStatus('processing');
      setError(null);

      // Step 1: Use AI to refine document structure
      const enhancedContent = await aiEnhanceDocument(content);

      // Step 2: Generate PDF
      setStatus('generating');
      await generatePDF(enhancedContent, fileName || 'document.pdf');

      setStatus('completed');
      setTimeout(() => setStatus('idle'), 3000);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unexpected error occurred during transformation.");
      setStatus('error');
    }
  };

  const triggerFileInput = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center px-6 py-12 transition-colors duration-500">
      <Header />

      <main className="w-full max-w-4xl flex flex-col items-center space-y-12 mt-16">
        <TransformVisual isProcessing={status === 'processing' || status === 'generating'} />

        <div className="w-full max-w-md space-y-8 flex flex-col items-center">
          <FileUploader 
            onFileSelect={handleFileSelect}
            fileName={fileName}
            status={status}
            triggerFileInput={triggerFileInput}
            fileInputRef={fileInputRef}
          />

          <button
            onClick={startTransformation}
            disabled={status !== 'idle' || !content}
            className={`group relative flex flex-col items-center space-y-4 transition-all duration-300 transform hover:scale-105 active:scale-95 ${
              !content ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'
            }`}
          >
            <div className={`w-32 h-32 rounded-full flex items-center justify-center shadow-xl transition-all duration-500 ${
              status === 'completed' ? 'bg-emerald-600' : 'bg-emerald-500'
            }`}>
              <svg 
                className={`w-16 h-16 text-white transition-all duration-500 ${status === 'completed' ? 'scale-110' : ''}`}
                fill="none" 
                viewBox="0 0 24 24" 
                stroke="currentColor"
              >
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" />
              </svg>
            </div>
            <span className="text-xl font-bold uppercase tracking-widest text-[#111827]">
              {status === 'idle' ? 'Transform Document' : 
               status === 'processing' ? 'AI Processing...' : 
               status === 'generating' ? 'Generating PDF...' : 
               status === 'completed' ? 'Success' : 'Transform Document'}
            </span>
          </button>

          {error && (
            <div className="p-4 bg-red-50 border border-red-200 text-red-600 rounded-lg text-sm font-medium w-full text-center">
              {error}
            </div>
          )}

          <ProgressIndicator status={status} />
        </div>
      </main>

      <footer className="mt-24 text-gray-400 text-xs tracking-widest uppercase">
        Enterprise Standard • Secure SSL • AI-Optimized
      </footer>
    </div>
  );
};

export default App;

