import React, { useState, useRef } from 'react';
import { Header } from './components/Header';
import { TransformVisual } from './components/TransformVisual';
import { FileUploader } from './components/FileUploader';
import { ProgressIndicator } from './components/ProgressIndicator';
import { SupportChat } from './components/SupportChat';
import { aiEnhanceDocument, DocumentPayload } from './services/geminiService';
import { generatePDF } from './utils/pdfHelper';

export type Status = 'idle' | 'uploading' | 'processing' | 'generating' | 'completed' | 'error';

const App: React.FC = () => {
  const [status, setStatus] = useState<Status>('idle');
  const [fileName, setFileName] = useState<string | null>(null);
  const [filePayload, setFilePayload] = useState<DocumentPayload | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    setStatus('uploading');

    const isText = file.name.endsWith('.txt') || file.name.endsWith('.md') || file.name.endsWith('.rtf');
    const reader = new FileReader();

    reader.onload = (event) => {
      let data = event.target?.result as string;

      // If it's a binary file read as DataURL, we need to extract just the base64 part
      if (!isText && data.includes('base64,')) {
        data = data.split('base64,')[1];
      }

      setFilePayload({
        data,
        mimeType: file.type || (isText ? 'text/plain' : 'application/octet-stream'),
        isText
      });
      setStatus('idle');
    };

    reader.onerror = () => {
      setError("Failed to read the file.");
      setStatus('error');
    };

    if (isText) {
      reader.readAsText(file);
    } else {
      reader.readAsDataURL(file);
    }
  };

  const startTransformation = async () => {
    if (!filePayload) {
      setError("Please select a document first.");
      return;
    }

    try {
      setStatus('processing');
      setError(null);

      // Step 1: Use AI to refine document structure
      // Gemini can handle .docx via inlineData
      const enhancedContent = await aiEnhanceDocument(filePayload);

      // Step 2: Generate PDF
      setStatus('generating');
      await generatePDF(enhancedContent, fileName || 'document.pdf');

      setStatus('completed');
      setTimeout(() => setStatus('idle'), 3000);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unexpected error occurred during transformation.");
      setStatus('error');
    }
  };

  const triggerFileInput = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center px-6 py-12 transition-colors duration-500 selection:bg-black selection:text-white">
      <Header />

      <main className="w-full max-w-4xl flex flex-col items-center space-y-12 mt-16">
        <TransformVisual isProcessing={status === 'processing' || status === 'generating'} />

        <div className="w-full max-w-md space-y-8 flex flex-col items-center">
          <FileUploader 
            onFileSelect={handleFileSelect}
            fileName={fileName}
            status={status}
            triggerFileInput={triggerFileInput}
            fileInputRef={fileInputRef}
          />

          <button
            onClick={startTransformation}
            disabled={status !== 'idle' || !filePayload}
            className={`group relative flex flex-col items-center space-y-4 transition-all duration-300 transform hover:scale-105 active:scale-95 ${
              !filePayload ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'
            }`}
          >
            <div className={`w-32 h-32 rounded-full flex items-center justify-center shadow-2xl transition-all duration-500 ${
              status === 'completed' ? 'bg-emerald-700' : 'bg-black hover:bg-gray-800'
            }`}>
              <svg 
                className={`w-16 h-16 text-white transition-all duration-500 ${status === 'completed' ? 'scale-110' : ''}`}
                fill="none" 
                viewBox="0 0 24 24" 
                stroke="currentColor"
              >
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" />
              </svg>
            </div>
            <span className="text-sm font-bold uppercase tracking-[0.3em] text-[#111827]">
              {status === 'idle' ? 'Transform Document' : 
               status === 'processing' ? 'AI Processing...' : 
               status === 'generating' ? 'Generating PDF...' : 
               status === 'completed' ? 'Success' : 'Transform Document'}
            </span>
          </button>

          {error && (
            <div className="p-4 bg-red-50 border border-red-200 text-red-600 rounded text-xs font-bold uppercase tracking-widest w-full text-center">
              {error}
            </div>
          )}

          <ProgressIndicator status={status} />
        </div>
      </main>

      <footer className="mt-24 text-gray-400 text-[10px] tracking-[0.4em] uppercase font-medium">
        Enterprise Standard • Secure SSL • AI-Optimized
      </footer>

      <SupportChat />
    </div>
  );
};

