import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export interface DocumentPayload {
  data: string;
  mimeType: string;
  isText: boolean;
}

interface EnhancedDocument {
  title: string;
  sections: Array<{
    heading: string;
    body: string;
  }>;
  summary: string;
}

export const aiEnhanceDocument = async (payload: DocumentPayload): Promise<EnhancedDocument> => {
  const instruction = `
    I am providing a document. Please transform this into a professional, structured business document.
    1. Extract a clear title.
    2. Organize the content into logical sections with clear headings.
    3. Proofread and refine the tone to be professional and enterprise-ready.
    4. Provide a brief 1-sentence executive summary at the start.
  `;

  const contents = {
    parts: [
      { text: instruction },
      payload.isText 
        ? { text: `Document Content:\n${payload.data}` } 
        : { inlineData: { data: payload.data, mimeType: payload.mimeType } }
    ]
  };

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: contents,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            summary: { type: Type.STRING },
            sections: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  heading: { type: Type.STRING },
                  body: { type: Type.STRING }
                },
                required: ["heading", "body"]
              }
            }
          },
          required: ["title", "summary", "sections"]
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return result as EnhancedDocument;
  } catch (error) {
    console.error("Gemini AI Transformation Error:", error);
    // Fallback if AI fails or doesn't support the specific binary format
    return {
      title: "Transformed Document",
      summary: "This document was converted without AI enhancement due to a processing issue.",
      sections: [{ heading: "Main Content", body: payload.isText ? payload.data : "Binary content extracted." }]
    };
  }
};

