import React, { useEffect, useState } from 'react';

interface Props {
  onComplete: () => void;
}

export const LaunchScreen: React.FC<Props> = ({ onComplete }) => {
  const [stage, setStage] = useState(0);

  useEffect(() => {
    // Stage 1: Main Title Focus (0.5s)
    const t1 = setTimeout(() => setStage(1), 500);
    // Stage 2: Subhead Reveal (1.5s)
    const t2 = setTimeout(() => setStage(2), 1500);
    // Stage 3: Pixelated Line Reveal (2.5s)
    const t3 = setTimeout(() => setStage(3), 2500);
    // Stage 4: Exit (4.0s)
    const t4 = setTimeout(() => setStage(4), 4000);
    // Stage 5: Done (4.5s)
    const t5 = setTimeout(() => onComplete(), 4500);

    return () => {
      clearTimeout(t1);
      clearTimeout(t2);
      clearTimeout(t3);
      clearTimeout(t4);
      clearTimeout(t5);
    };
  }, [onComplete]);

  return (
    <div className={`fixed inset-0 z-[100] bg-white flex flex-col items-center justify-center transition-opacity duration-1000 ${stage === 4 ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}>
      <div className="flex flex-col items-center space-y-4">
        {/* Main Headline: JustPDFIt */}
        <h1 className={`text-7xl md:text-9xl font-bold tracking-tighter text-black transition-all duration-1000 ease-out ${
          stage >= 1 ? 'blur-0 opacity-100 scale-100' : 'blur-xl opacity-0 scale-95'
        }`}>
          JustPDFIt
        </h1>

        {/* Subhead: PDF, Powered by AI */}
        <h2 className={`text-xl md:text-2xl font-light tracking-[0.3em] uppercase text-gray-400 transition-all duration-700 delay-300 ${
          stage >= 2 ? 'translate-y-0 opacity-100' : 'translate-y-4 opacity-0'
        }`}>
          PDF, Powered by AI
        </h2>

        {/* Supporting Line: Pixelated Style */}
        <p className={`text-[10px] md:text-xs font-mono uppercase tracking-[0.5em] text-gray-300 transition-all duration-700 delay-500 ${
          stage >= 3 ? 'opacity-100' : 'opacity-0'
        }`} style={{ 
          imageRendering: 'pixelated',
          textShadow: stage >= 3 ? '1px 1px 0px rgba(0,0,0,0.05)' : 'none'
        }}>
          A Document Transformation Experience
        </p>
      </div>

      {/* Visual Accent */}
      <div className={`absolute bottom-20 w-32 h-[1px] bg-gray-100 transition-all duration-1000 ${stage >= 1 ? 'w-64 opacity-100' : 'w-0 opacity-0'}`}></div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Header } from './components/Header';
import { TransformVisual } from './components/TransformVisual';
import { FileUploader } from './components/FileUploader';
import { ProgressIndicator } from './components/ProgressIndicator';
import { SupportChat } from './components/SupportChat';
import { LaunchScreen } from './components/LaunchScreen';
import { aiEnhanceDocument, DocumentPayload } from './services/geminiService';
import { generatePDF } from './utils/pdfHelper';

export type Status = 'idle' | 'uploading' | 'processing' | 'generating' | 'completed' | 'error';

const App: React.FC = () => {
  const [isLaunching, setIsLaunching] = useState(true);
  const [status, setStatus] = useState<Status>('idle');
  const [fileName, setFileName] = useState<string | null>(null);
  const [filePayload, setFilePayload] = useState<DocumentPayload | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    setStatus('uploading');

    const isText = file.name.endsWith('.txt') || file.name.endsWith('.md') || file.name.endsWith('.rtf');
    const reader = new FileReader();

    reader.onload = (event) => {
      let data = event.target?.result as string;

      // If it's a binary file read as DataURL, we need to extract just the base64 part
      if (!isText && data.includes('base64,')) {
        data = data.split('base64,')[1];
      }

      setFilePayload({
        data,
        mimeType: file.type || (isText ? 'text/plain' : 'application/octet-stream'),
        isText
      });
      setStatus('idle');
    };

    reader.onerror = () => {
      setError("Failed to read the file.");
      setStatus('error');
    };

    if (isText) {
      reader.readAsText(file);
    } else {
      reader.readAsDataURL(file);
    }
  };

  const startTransformation = async () => {
    if (!filePayload) {
      setError("Please select a document first.");
      return;
    }

    try {
      setStatus('processing');
      setError(null);

      // Step 1: Use AI to refine document structure
      const enhancedContent = await aiEnhanceDocument(filePayload);

      // Step 2: Generate PDF
      setStatus('generating');
      await generatePDF(enhancedContent, fileName || 'document.pdf');

      setStatus('completed');
      setTimeout(() => setStatus('idle'), 3000);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unexpected error occurred during transformation.");
      setStatus('error');
    }
  };

  const triggerFileInput = () => {
    fileInputRef.current?.click();
  };

  if (isLaunching) {
    return <LaunchScreen onComplete={() => setIsLaunching(false)} />;
  }

  return (
    <div className="min-h-screen flex flex-col items-center justify-center px-6 py-12 transition-colors duration-500 selection:bg-emerald-100 selection:text-emerald-900 animate-in fade-in duration-1000">
      <Header />

      <main className="w-full max-w-4xl flex flex-col items-center space-y-12 mt-16">
        <TransformVisual isProcessing={status === 'processing' || status === 'generating'} />

        <div className="w-full max-w-md space-y-8 flex flex-col items-center">
          <FileUploader 
            onFileSelect={handleFileSelect}
            fileName={fileName}
            status={status}
            triggerFileInput={triggerFileInput}
            fileInputRef={fileInputRef}
          />

          <button
            onClick={startTransformation}
            disabled={status !== 'idle' || !filePayload}
            className={`group relative flex flex-col items-center space-y-4 transition-all duration-300 transform hover:scale-105 active:scale-95 ${
              !filePayload ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'
            }`}
          >
            <div className={`w-32 h-32 rounded-full flex items-center justify-center shadow-2xl transition-all duration-500 ${
              status === 'completed' 
                ? 'bg-emerald-700' 
                : 'bg-emerald-600 hover:bg-emerald-500'
            }`}>
              <svg 
                className={`w-16 h-16 text-white transition-all duration-500 ${status === 'completed' ? 'scale-110' : ''}`}
                fill="none" 
                viewBox="0 0 24 24" 
                stroke="currentColor"
              >
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
              </svg>
            </div>
            <span className="text-sm font-bold uppercase tracking-[0.3em] text-[#111827]">
              {status === 'idle' ? 'Transform Document' : 
               status === 'processing' ? 'AI Processing...' : 
               status === 'generating' ? 'Generating PDF...' : 
               status === 'completed' ? 'Success' : 'Transform Document'}
            </span>
          </button>

          {error && (
            <div className="p-4 bg-red-50 border border-red-200 text-red-600 rounded text-xs font-bold uppercase tracking-widest w-full text-center">
              {error}
            </div>
          )}

          <ProgressIndicator status={status} />
        </div>
      </main>

      <footer className="mt-24 text-gray-400 text-[10px] tracking-[0.4em] uppercase font-medium">
        Enterprise Standard • Secure SSL • AI-Optimized
      </footer>

      <SupportChat />
    </div>
  );
};

export default App;

