import React, { useState, useRef } from 'react';
import mammoth from 'mammoth';
import { Header } from './components/Header';
import { TransformVisual } from './components/TransformVisual';
import { FileUploader } from './components/FileUploader';
import { ProgressIndicator } from './components/ProgressIndicator';
import { SupportChat } from './components/SupportChat';
import { LaunchScreen } from './components/LaunchScreen';
import { CollapsibleMenu } from './components/CollapsibleMenu';
import { AboutPage } from './components/AboutPage';
import { HowItWorksPage } from './components/HowItWorksPage';
import { WhyUseItPage } from './components/WhyUseItPage';
import { aiEnhanceDocument, DocumentPayload } from './services/geminiService';
import { generatePDF } from './utils/pdfHelper';

export type Status = 'idle' | 'uploading' | 'processing' | 'generating' | 'completed' | 'error';
export type View = 'home' | 'about' | 'how-it-works' | 'why-use-it';

const App: React.FC = () => {
  const [isLaunching, setIsLaunching] = useState(true);
  const [currentView, setCurrentView] = useState<View>('home');
  const [status, setStatus] = useState<Status>('idle');
  const [fileName, setFileName] = useState<string | null>(null);
  const [filePayload, setFilePayload] = useState<DocumentPayload | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    setStatus('uploading');
    setError(null);

    const extension = file.name.split('.').pop()?.toLowerCase();
    const isText = ['txt', 'md', 'rtf'].includes(extension || '');
    const isDocx = extension === 'docx';
    const isDoc = extension === 'doc';

    try {
      if (isDocx) {
        const arrayBuffer = await file.arrayBuffer();
        const result = await mammoth.extractRawText({ arrayBuffer });
        setFilePayload({ data: result.value, mimeType: 'text/plain', isText: true });
        setStatus('idle');
      } else if (isText) {
        const text = await file.text();
        setFilePayload({ data: text, mimeType: file.type || 'text/plain', isText: true });
        setStatus('idle');
      } else if (isDoc) {
        const text = await file.text();
        setFilePayload({ data: text, mimeType: 'text/plain', isText: true });
        setError("Note: .doc (legacy) files may have limited AI structural recognition. .docx or .txt is recommended.");
        setStatus('idle');
      } else {
        const reader = new FileReader();
        reader.onload = (event) => {
          let data = event.target?.result as string;
          if (data && typeof data === 'string' && data.includes('base64,')) {
            data = data.split('base64,')[1];
          }
          setFilePayload({ data: data as string, mimeType: file.type || 'application/octet-stream', isText: false });
          setStatus('idle');
        };
        reader.readAsDataURL(file);
      }
    } catch (err: any) {
      console.error("File loading error:", err);
      setError("Failed to process the document format. Please try a different file.");
      setStatus('error');
    }
  };

  const startTransformation = async () => {
    if (!filePayload) {
      setError("Please select a document first.");
      return;
    }
    try {
      setStatus('processing');
      setError(null);
      const enhancedContent = await aiEnhanceDocument(filePayload);
      setStatus('generating');
      await generatePDF(enhancedContent, fileName || 'document.pdf');
      setStatus('completed');
      setTimeout(() => setStatus('idle'), 3000);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unexpected error occurred during transformation.");
      setStatus('error');
    }
  };

  const triggerFileInput = () => fileInputRef.current?.click();

  if (isLaunching) {
    return <LaunchScreen onComplete={() => setIsLaunching(false)} />;
  }

  const isWorking = status === 'processing' || status === 'generating';

  const renderContent = () => {
    switch(currentView) {
      case 'about': return <AboutPage />;
      case 'how-it-works': return <HowItWorksPage />;
      case 'why-use-it': return <WhyUseItPage />;
      default: return (
        <>
          <Header />
          <main className="w-full max-w-4xl flex flex-col items-center space-y-12 mt-16">
            <TransformVisual isProcessing={isWorking} />
            <div className="w-full max-w-md space-y-8 flex flex-col items-center">
              <FileUploader 
                onFileSelect={handleFileSelect}
                fileName={fileName}
                status={status}
                triggerFileInput={triggerFileInput}
                fileInputRef={fileInputRef}
              />
              <button
                onClick={startTransformation}
                disabled={status !== 'idle' || !filePayload}
                className={`group relative flex flex-col items-center space-y-4 transition-all duration-300 transform ${
                  isWorking ? 'scale-105' : 'hover:scale-105 active:scale-95'
                } ${!filePayload ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}`}
              >
                {isWorking && (
                  <div className="absolute -inset-2 rounded-full border-2 border-dashed border-emerald-400 animate-[spin_4s_linear_infinite] opacity-50"></div>
                )}
                <div className={`w-32 h-32 rounded-full flex items-center justify-center shadow-2xl transition-all duration-500 relative overflow-hidden ${
                  status === 'completed' ? 'bg-emerald-700' : isWorking ? 'bg-emerald-600 shadow-[0_0_30px_rgba(16,185,129,0.4)] animate-pulse' : 'bg-emerald-600 hover:bg-emerald-500'
                }`}>
                  {isWorking && <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full animate-[shimmer_2s_infinite]"></div>}
                  <svg className={`w-16 h-16 text-white transition-all duration-500 ${status === 'completed' ? 'scale-110' : ''} ${isWorking ? 'opacity-50' : 'opacity-100'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                  </svg>
                </div>
                <span className={`text-sm font-bold uppercase tracking-[0.3em] text-[#111827] transition-all duration-300 ${isWorking ? 'opacity-80' : 'opacity-100'}`}>
                  {status === 'idle' ? 'Transform Document' : status === 'processing' ? 'AI Processing...' : status === 'generating' ? 'Generating PDF...' : status === 'completed' ? 'Success' : 'Transform Document'}
                </span>
              </button>
              {error && <div className="p-4 bg-red-50 border border-red-200 text-red-600 rounded text-xs font-bold uppercase tracking-widest w-full text-center">{error}</div>}
              <ProgressIndicator status={status} />
            </div>
          </main>
        </>
      );
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center px-6 py-12 transition-colors duration-500 selection:bg-emerald-100 selection:text-emerald-900 animate-in fade-in duration-1000">
      <CollapsibleMenu onNavigate={setCurrentView} currentView={currentView} />

      {renderContent()}

      <footer className="mt-24 flex flex-col items-center space-y-1 text-gray-400 text-[10px] tracking-[0.2em] md:tracking-[0.4em] uppercase font-medium whitespace-nowrap text-center">
        <p>Enterprise Standard • Secure SSL • AI-Optimized</p>
        <p>Built by Blue Dot Tech</p>
      </footer>

      <SupportChat />

      <style>{`
        @keyframes shimmer { 100% { transform: translateX(100%); } }
      `}</style>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

export interface DocumentPayload {
  data: string;
  mimeType: string;
  isText: boolean;
}

interface EnhancedDocument {
  title: string;
  sections: Array<{
    heading: string;
    body: string;
  }>;
  summary: string;
}

export const aiEnhanceDocument = async (payload: DocumentPayload): Promise<EnhancedDocument> => {
  // Initialize AI client right before the call as per best practices
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const instruction = `
    I am providing a document. Please transform this into a professional, structured business document.
    1. Extract a clear title.
    2. Organize the content into logical sections with clear headings.
    3. Proofread and refine the tone to be professional and enterprise-ready.
    4. Provide a brief 1-sentence executive summary at the start.
  `;

  const contents = {
    parts: [
      { text: instruction },
      payload.isText 
        ? { text: `Document Content:\n${payload.data}` } 
        : { inlineData: { data: payload.data, mimeType: payload.mimeType } }
    ]
  };

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview", // Upgraded to Pro for complex reasoning
      contents: contents,
      config: {
        thinkingConfig: { thinkingBudget: 4096 }, // Added thinking budget for better structural analysis
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            summary: { type: Type.STRING },
            sections: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  heading: { type: Type.STRING },
                  body: { type: Type.STRING }
                },
                required: ["heading", "body"]
              }
            }
          },
          required: ["title", "summary", "sections"]
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return result as EnhancedDocument;
  } catch (error) {
    console.error("Gemini AI Transformation Error:", error);
    // Fallback if AI fails or doesn't support the specific binary format
    return {
      title: "Transformed Document",
      summary: "This document was converted without AI enhancement due to a processing issue.",
      sections: [{ heading: "Main Content", body: payload.isText ? payload.data : "Binary content extracted." }]
    };
  }
};

