      If user says anything that doesn't clearly map to the other four, default to: "Please upload a document to begin."`,
    },
  });
};

import React, { useState, useRef, useEffect } from 'react';
import { createSupportChat } from '../services/chatService';
import { GoogleGenAI, GenerateContentResponse } from '@google/genai';

interface Message {
  role: 'user' | 'model';
  text: string;
}

export const SupportChat: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'Hello. I am the JustPDFIt assistant.\nHow can I assist with your document transformation today?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatInstance = useRef<any>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const initChat = () => {
    if (!chatInstance.current) {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      chatInstance.current = createSupportChat(ai);
    }
  };

  const toggleChat = () => {
    setIsOpen(!isOpen);
    if (!isOpen) {
      initChat();
    }
  };

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsLoading(true);

    try {
      initChat();

      const responseStream = await chatInstance.current.sendMessageStream({ message: userMessage });

      let fullText = '';
      setMessages(prev => [...prev, { role: 'model', text: '' }]);

      for await (const chunk of responseStream) {
        const chunkResponse = chunk as GenerateContentResponse;
        fullText += chunkResponse.text || '';
        setMessages(prev => {
          const newMessages = [...prev];
          newMessages[newMessages.length - 1].text = fullText;
          return newMessages;
        });
      }
    } catch (error) {
      console.error('Chat error:', error);
      setMessages(prev => [...prev, { role: 'model', text: 'Please upload a document to begin.' }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-8 right-8 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="w-80 md:w-96 h-[450px] bg-white rounded-2xl shadow-2xl flex flex-col overflow-hidden mb-4 border border-gray-100 animate-in slide-in-from-bottom-4 duration-300">
          <div className="bg-[#111827] p-4 flex justify-between items-center">
            <div>
              <h3 className="text-white font-bold text-sm tracking-tight">Support Assistant</h3>
              <p className="text-gray-400 text-[10px] uppercase tracking-widest font-medium">Enterprise Agent Active</p>
            </div>
            <button onClick={toggleChat} className="text-gray-400 hover:text-white transition-colors">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed shadow-sm whitespace-pre-wrap ${
                  m.role === 'user' 
                  ? 'bg-[#111827] text-white rounded-br-none' 
                  : 'bg-white text-[#111827] border border-gray-100 rounded-bl-none'
                }`}>
                  {m.text || (isLoading && i === messages.length - 1 ? '...' : '')}
                </div>
              </div>
            ))}
          </div>

          <form onSubmit={handleSend} className="p-4 bg-white border-t border-gray-100 flex items-center space-x-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Type your question..."
              className="flex-1 text-sm focus:outline-none placeholder-gray-400"
              disabled={isLoading}
            />
            <button 
              type="submit" 
              disabled={isLoading || !input.trim()}
              className="p-2 text-gray-400 hover:text-[#111827] transition-colors disabled:opacity-30"
            >
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
              </svg>
            </button>
          </form>
        </div>
      )}

      <button
        onClick={toggleChat}
        className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg transition-all duration-300 transform hover:scale-110 active:scale-90 ${
          isOpen ? 'bg-gray-100 text-[#111827]' : 'bg-[#111827] text-white'
        }`}
      >
        {isOpen ? (
          <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
          </svg>
        ) : (
          <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
        )}
      </button>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import mammoth from 'mammoth';
import { Header } from './components/Header';
import { TransformVisual } from './components/TransformVisual';
import { FileUploader } from './components/FileUploader';
import { ProgressIndicator } from './components/ProgressIndicator';
import { SupportChat } from './components/SupportChat';
import { LaunchScreen } from './components/LaunchScreen';
import { CollapsibleMenu } from './components/CollapsibleMenu';
import { AboutPage } from './components/AboutPage';
import { HowItWorksPage } from './components/HowItWorksPage';
import { WhyUseItPage } from './components/WhyUseItPage';
import { aiEnhanceDocument, DocumentPayload } from './services/geminiService';
import { generatePDF } from './utils/pdfHelper';

export type Status = 'idle' | 'uploading' | 'processing' | 'generating' | 'completed' | 'error';
export type View = 'home' | 'about' | 'how-it-works' | 'why-use-it';

const App: React.FC = () => {
  const [isLaunching, setIsLaunching] = useState(true);
  const [currentView, setCurrentView] = useState<View>('home');
  const [status, setStatus] = useState<Status>('idle');
  const [fileName, setFileName] = useState<string | null>(null);
  const [filePayload, setFilePayload] = useState<DocumentPayload | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    setStatus('uploading');
    setError(null);
    setFilePayload(null);

    const extension = file.name.split('.').pop()?.toLowerCase();
    const isDocx = extension === 'docx';
    const isPdf = extension === 'pdf';
    const isText = ['txt', 'md', 'rtf', 'csv'].includes(extension || '');

    try {
      if (isDocx) {
        // Extract text from DOCX using Mammoth
        const arrayBuffer = await file.arrayBuffer();
        const result = await mammoth.extractRawText({ arrayBuffer });
        if (!result.value.trim()) throw new Error("Document appears to be empty.");
        setFilePayload({ data: result.value, mimeType: 'text/plain', isText: true });
        setStatus('idle');
      } else if (isPdf) {
        // Pass PDF directly to Gemini (it supports application/pdf)
        const reader = new FileReader();
        reader.onload = () => {
          const base64 = (reader.result as string).split(',')[1];
          setFilePayload({ data: base64, mimeType: 'application/pdf', isText: false });
          setStatus('idle');
        };
        reader.onerror = () => { throw new Error("Failed to read PDF file."); };
        reader.readAsDataURL(file);
      } else if (isText) {
        // Standard text files
        const text = await file.text();
        setFilePayload({ data: text, mimeType: 'text/plain', isText: true });
        setStatus('idle');
      } else {
        // Fallback for .doc and others: attempt to read as binary/base64
        // Note: Gemini has limited support for legacy .doc binary, 
        // so we treat it as application/octet-stream and hope for the best or rely on Pro's reasoning
        const reader = new FileReader();
        reader.onload = () => {
          const base64 = (reader.result as string).split(',')[1];
          setFilePayload({ data: base64, mimeType: file.type || 'application/octet-stream', isText: false });
          setStatus('idle');
        };
        reader.readAsDataURL(file);
        if (extension === 'doc') {
          setError("Note: Legacy .doc files may have reduced accuracy. .docx or .pdf is preferred.");
        }
      }
    } catch (err: any) {
      console.error("File processing error:", err);
      setError(err.message || "Failed to process the document. Please try a different format.");
      setStatus('error');
      setFileName(null);
    }
  };

  const startTransformation = async () => {
    if (!filePayload) {
      setError("Please select a valid document first.");
      return;
    }
    try {
      setStatus('processing');
      setError(null);
      const enhancedContent = await aiEnhanceDocument(filePayload);
      setStatus('generating');
      await generatePDF(enhancedContent, fileName || 'transformed-document.pdf');
      setStatus('completed');
      setTimeout(() => setStatus('idle'), 3000);
    } catch (err: any) {
      console.error("Transformation error:", err);
      setError(err.message || "An unexpected error occurred during AI transformation.");
      setStatus('error');
    }
  };

  const triggerFileInput = () => fileInputRef.current?.click();

  if (isLaunching) {
    return <LaunchScreen onComplete={() => setIsLaunching(false)} />;
  }

  const isWorking = status === 'processing' || status === 'generating';

  const renderContent = () => {
    switch(currentView) {
      case 'about': return <AboutPage />;
      case 'how-it-works': return <HowItWorksPage />;
      case 'why-use-it': return <WhyUseItPage />;
      default: return (
        <>
          <Header />
          <main className="w-full max-w-4xl flex flex-col items-center space-y-12 mt-16">
            <TransformVisual isProcessing={isWorking} />
            <div className="w-full max-w-md space-y-8 flex flex-col items-center">
              <FileUploader 
                onFileSelect={handleFileSelect}
                fileName={fileName}
                status={status}
                triggerFileInput={triggerFileInput}
                fileInputRef={fileInputRef}
              />
              <button
                onClick={startTransformation}
                disabled={status !== 'idle' || !filePayload}
                className={`group relative flex flex-col items-center space-y-4 transition-all duration-300 transform ${
                  isWorking ? 'scale-105' : 'hover:scale-105 active:scale-95'
                } ${(!filePayload || status !== 'idle') ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}`}
              >
                {isWorking && (
                  <div className="absolute -inset-2 rounded-full border-2 border-dashed border-emerald-400 animate-[spin_4s_linear_infinite] opacity-50"></div>
                )}
                <div className={`w-32 h-32 rounded-full flex items-center justify-center shadow-2xl transition-all duration-500 relative overflow-hidden ${
                  status === 'completed' ? 'bg-emerald-700' : isWorking ? 'bg-emerald-600 shadow-[0_0_30px_rgba(16,185,129,0.4)] animate-pulse' : 'bg-emerald-600 hover:bg-emerald-500'
                }`}>
                  {isWorking && <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full animate-[shimmer_2s_infinite]"></div>}
                  <svg className={`w-16 h-16 text-white transition-all duration-500 ${status === 'completed' ? 'scale-110' : ''} ${isWorking ? 'opacity-50' : 'opacity-100'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                  </svg>
                </div>
